const html = $input.first().json.data;
const url = $('Webhook Trigger').first().json.body.url;

// Extract title
const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : '';

// Extract meta description
const metaDescMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["'](.*?)["'][^>]*>/i)
  || html.match(/<meta[^>]*content=["'](.*?)["'][^>]*name=["']description["'][^>]*>/i);
const metaDescription = metaDescMatch ? metaDescMatch[1].trim() : '';

// Extract meta keywords
const metaKeyMatch = html.match(/<meta[^>]*name=["']keywords["'][^>]*content=["'](.*?)["'][^>]*>/i);
const metaKeywords = metaKeyMatch ? metaKeyMatch[1].trim() : '';

// Extract all headings
const h1s = (html.match(/<h1[^>]*>(.*?)<\/h1>/gi) || []).map(h => h.replace(/<[^>]+>/g, '').trim());
const h2s = (html.match(/<h2[^>]*>(.*?)<\/h2>/gi) || []).map(h => h.replace(/<[^>]+>/g, '').trim());
const h3s = (html.match(/<h3[^>]*>(.*?)<\/h3>/gi) || []).map(h => h.replace(/<[^>]+>/g, '').trim());

// Extract images and alt text
const images = html.match(/<img[^>]+>/gi) || [];
const totalImages = images.length;
const imagesWithAlt = images.filter(img => /alt=["'][^"']+["']/i.test(img)).length;
const imagesWithoutAlt = totalImages - imagesWithAlt;

// Extract internal and external links
const allLinks = html.match(/<a[^>]*href=["'](.*?)["'][^>]*>/gi) || [];
const domain = new URL(url).hostname;
let internalLinks = 0;
let externalLinks = 0;
for (const link of allLinks) {
  const hrefMatch = link.match(/href=["'](.*?)["']/i);
  if (hrefMatch) {
    const href = hrefMatch[1];
    if (href.startsWith('/') || href.includes(domain)) internalLinks++;
    else if (href.startsWith('http')) externalLinks++;
  }
}

// Check canonical
const canonicalMatch = html.match(/<link[^>]*rel=["']canonical["'][^>]*href=["'](.*?)["'][^>]*>/i);
const canonical = canonicalMatch ? canonicalMatch[1] : '';

// Check viewport meta (mobile-friendly)
const hasViewport = /<meta[^>]*name=["']viewport["']/i.test(html);

// Check Open Graph tags
const hasOgTitle = /<meta[^>]*property=["']og:title["']/i.test(html);
const hasOgDesc = /<meta[^>]*property=["']og:description["']/i.test(html);
const hasOgImage = /<meta[^>]*property=["']og:image["']/i.test(html);

// Check Twitter Card
const hasTwitterCard = /<meta[^>]*name=["']twitter:card["']/i.test(html);

// Check Schema/JSON-LD
const schemaMatches = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>(.*?)<\/script>/gis) || [];
const hasSchema = schemaMatches.length > 0;

// Check robots meta
const robotsMatch = html.match(/<meta[^>]*name=["']robots["'][^>]*content=["'](.*?)["'][^>]*>/i);
const robotsMeta = robotsMatch ? robotsMatch[1] : 'not set';

// Word count (strip all HTML)
const textContent = html.replace(/<script[^>]*>.*?<\/script>/gis, '').replace(/<style[^>]*>.*?<\/style>/gis, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const wordCount = textContent.split(' ').filter(w => w.length > 0).length;

// Check for lang attribute
const langMatch = html.match(/<html[^>]*lang=["'](.*?)["']/i);
const htmlLang = langMatch ? langMatch[1] : 'not set';

return [{
  json: {
    url,
    title,
    titleLength: title.length,
    metaDescription,
    metaDescLength: metaDescription.length,
    metaKeywords,
    h1s,
    h1Count: h1s.length,
    h2s,
    h2Count: h2s.length,
    h3s,
    h3Count: h3s.length,
    totalImages,
    imagesWithAlt,
    imagesWithoutAlt,
    internalLinks,
    externalLinks,
    canonical,
    hasViewport,
    hasOgTitle,
    hasOgDesc,
    hasOgImage,
    hasTwitterCard,
    hasSchema,
    schemaCount: schemaMatches.length,
    robotsMeta,
    wordCount,
    htmlLang
  }
}];

